const raw = $input.first().json.content;
const cleaned = raw.replace(/```json/gi,'').replace(/```/g,'').trim();
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
if (start === -1 || end === -1) throw new Error('Nessun JSON trovato: ' + raw);

let parsed;
try { parsed = JSON.parse(cleaned.substring(start, end + 1)); }
catch(e) { throw new Error('JSON non valido: ' + e.message); }

// ── LOOKUP TABLE ──────────────────────────────────────────────
const TRACK_DEFAULTS = {
  kick:         { type:'audio',      channel:'mono',   color:'red',    input_channel:'Ch. 1', send_drums:true  },
  snare:        { type:'audio',      channel:'mono',   color:'red',    input_channel:'Ch. 2', send_drums:true  },
  tom:          { type:'audio',      channel:'mono',   color:'red',    input_channel:'auto',  send_drums:true  },
  'floor tom':  { type:'audio',      channel:'mono',   color:'red',    input_channel:'auto',  send_drums:true  },
  'hi-hat':     { type:'audio',      channel:'mono',   color:'red',    input_channel:'auto',  send_drums:true  },
  hihat:        { type:'audio',      channel:'mono',   color:'red',    input_channel:'auto',  send_drums:true  },
  cymbal:       { type:'audio',      channel:'mono',   color:'red',    input_channel:'auto',  send_drums:true  },
  cymbals:      { type:'audio',      channel:'mono',   color:'red',    input_channel:'auto',  send_drums:true  },
  hats:         { type:'audio',      channel:'mono',   color:'red',    input_channel:'auto',  send_drums:true  },
  'synth pad':  { type:'instrument', channel:'stereo', color:'cyan',   device:'Analog',       send_synth:true  },
  'synth lead': { type:'instrument', channel:'stereo', color:'cyan',   device:'Analog',       send_synth:true  },
  lead:         { type:'instrument', channel:'stereo', color:'cyan',   device:'Analog',       send_synth:true  },
  overhead:     { type:'audio',      channel:'stereo', color:'orange', input_channel:'auto',  send_drums:true  },
  room:         { type:'audio',      channel:'stereo', color:'orange', input_channel:'auto',  send_drums:true  },
  bass:         { type:'audio',      channel:'mono',   color:'yellow', input_channel:'auto',  send_bass:true   },
  'bass di':    { type:'audio',      channel:'mono',   color:'yellow', input_channel:'auto',  send_bass:true   },
  guitar:       { type:'audio',      channel:'mono',   color:'green',  input_channel:'auto',  send_guitar:true },
  chitarra:     { type:'audio',      channel:'mono',   color:'green',  input_channel:'auto',  send_guitar:true },
  vocal:        { type:'audio',      channel:'mono',   color:'blue',   input_channel:'auto',  send_vocal:true  },
  vocals:       { type:'audio',      channel:'mono',   color:'blue',   input_channel:'auto',  send_vocal:true  },
  voce:         { type:'audio',      channel:'mono',   color:'blue',   input_channel:'auto',  send_vocal:true  },
  'drum rack':  { type:'instrument', channel:'stereo', color:'red',    device:'Drum Rack',    send_drums:true  },
  drumrack:     { type:'instrument', channel:'stereo', color:'red',    device:'Drum Rack',    send_drums:true  },
  synth:        { type:'instrument', channel:'stereo', color:'cyan',   device:'Analog',       send_synth:true  },
  pad:          { type:'instrument', channel:'stereo', color:'cyan',   device:'Analog',       send_synth:true  },
  analog:       { type:'instrument', channel:'stereo', color:'cyan',   device:'Analog',       send_synth:true  },
  wavetable:    { type:'instrument', channel:'stereo', color:'cyan',   device:'Wavetable',    send_synth:true  },
  operator:     { type:'instrument', channel:'stereo', color:'cyan',   device:'Operator',     send_synth:true  },
  piano:        { type:'instrument', channel:'stereo', color:'cyan',   device:'Electric',     send_synth:true  },
  keys:         { type:'instrument', channel:'stereo', color:'cyan',   device:'Electric',     send_synth:true  },
  sampler:      { type:'instrument', channel:'stereo', color:'purple', device:'Sampler',      send_synth:true  },
  impulse:      { type:'instrument', channel:'stereo', color:'purple', device:'Impulse',      send_drums:true  },
  'overhead stereo': { type:'audio',      channel:'stereo', color:'orange', input_channel:'auto', send_drums:true  },
  'voice lead':      { type:'audio',      channel:'mono',   color:'blue',   input_channel:'auto', send_vocal:true  },
  'lead vocal':      { type:'audio',      channel:'mono',   color:'blue',   input_channel:'auto', send_vocal:true  },
  'synth pad':       { type:'instrument', channel:'stereo', color:'cyan',   device:'Analog',      send_synth:true  },
  'synth lead':      { type:'instrument', channel:'stereo', color:'cyan',   device:'Analog',      send_synth:true  },
};

const BUS_DEFAULTS = {
  'reverb bus': { effects:['Hybrid Reverb'] },
  'delay bus':  { effects:['Echo']          },
  'echo bus':   { effects:['Echo']          },
  'chorus bus': { effects:['Chorus-Ensemble'] },
  'comp bus':   { effects:['Glue Compressor'] },
};

// ── BUILD SESSION JSON ────────────────────────────────────────
const busNames = (parsed.buses || []);
const hasReverb = busNames.some(b => b.toLowerCase().includes('reverb'));
const hasDelay  = busNames.some(b => b.toLowerCase().includes('delay'));

const tracks = [];
let audioChannelCounter = 1;
let id = 1;

for (const inst of (parsed.instruments || [])) {
  const key = inst.name.toLowerCase().trim();
  const def = TRACK_DEFAULTS[key] || {
    type: 'audio', channel: 'mono', color: 'gray', input_channel: 'auto'
  };

  const qty = inst.quantity || 1;
  for (let i = 0; i < qty; i++) {
    const trackName = qty > 1 ? `${inst.name} ${i+1}` : inst.name
      .split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

    const sendTo = [];
    if (hasReverb && (def.send_drums || def.send_guitar || def.send_vocal || def.send_synth)) {
      sendTo.push(busNames.find(b => b.toLowerCase().includes('reverb')));
    }
    if (hasDelay && (def.send_guitar || def.send_vocal || def.send_synth)) {
      sendTo.push(busNames.find(b => b.toLowerCase().includes('delay')));
    }

    const track = {
      id: id++,
      name: trackName,
      type: def.type,
      channel: def.channel,
      color: def.color,
      volume: 0.85,
      pan: 0,
      mute: false,
      effects: inst.effects || [],
      send_to: sendTo.filter(Boolean),
    };

    if (def.type === 'audio') {
      track.input_type = 'Ext. In';
      track.input_channel = def.input_channel === 'auto'
        ? `Ch. ${audioChannelCounter++}`
        : def.input_channel;
      if (def.input_channel !== 'auto') audioChannelCounter++;
    }

    if (def.device) track.device = def.device;

    tracks.push(track);
  }
}

const buses = busNames.map(name => {
  const key = name.toLowerCase().trim();
  const def = BUS_DEFAULTS[key] || { effects: [] };
  return {
    name,
    type: 'fx',
    color: 'purple',
    volume: 0.85,
    output: 'Master',
    effects: def.effects,
  };
});

const result = {
  session: {
    name: parsed.session_name || 'Session',
    tempo: parsed.tempo || 120,
    time_signature: parsed.time_signature || '4/4',
  },
  tracks,
  buses,
};

if (result.tracks.length === 0) {
  throw new Error('Nessuna traccia generata — controlla il prompt');
}

return [{ json: result }];
